let chart;
function renderChart() {
  const powiat = Number(appsmith.model.powiat || 0);
  const woj = Number(appsmith.model.woj || 0);
  const rok = appsmith.model.rok || "";
  const aos = Number(appsmith.model.aos || 0);
  const poradnia = appsmith.model.poradnia || "";
  const colors = [powiat > woj ? "#fca5a5" : powiat < woj ? "#bbf7d0" : "#6B778E", "#6B778E"];
  const el = document.getElementById("chart");
  if (!chart) {
    chart = echarts.init(el);
  }
  chart.setOption({
    title: {
      text: aos === 0 ? "Stosunek liczby poradni na 10 tys. mieszkańców powiatu do wartości dla woj. mazowieckiego" : "Stosunek liczby porad na 1 tyś. mieszkańcow powiatu do wartości dla woj. mazowieckiego",
      subtext: "Rok: " + rok + "\n\n" + poradnia,
      left: "center",
      top: 15,
      textStyle: {
        fontSize: 14,
        fontWeight: "bold",
        color: "#64748b"
      },
      subtextStyle: {
        fontSize: 12,
        fontWeight: "normal",
        color: "#374151"
      }
    },
    tooltip: {
      trigger: "axis",
      axisPointer: {
        type: "shadow"
      }
    },
    grid: {
      left: 70,
      right: 40,
      top: 110,
      bottom: 70
    },
    xAxis: {
      type: "category",
      data: [appsmith.model.powiatLabel || "powiat", "wartość dla woj. mazowieckiego"],
      axisTick: {
        alignWithLabel: true
      },
      axisLabel: {
        color: "#6B7280",
        fontSize: 13
      },
      axisLine: {
        lineStyle: {
          color: "#9CA3AF"
        }
      }
    },
    yAxis: {
      type: "value",
      name: aos === 0 ? "Liczba poradni" : "Liczba porad",
      nameLocation: "middle",
      nameGap: 50,
      axisLabel: {
        color: "#6B7280"
      },
      splitLine: {
        lineStyle: {
          color: "#E5E7EB"
        }
      }
    },
    series: [{
      name: rok,
      type: "bar",
      barWidth: "55%",
      data: [{
        value: powiat,
        itemStyle: {
          color: colors[0]
        }
      }, {
        value: woj,
        itemStyle: {
          color: colors[1]
        }
      }],
      label: {
        show: true,
        position: "top",
        fontSize: 13,
        fontWeight: "normal",
        color: "#374151",
        formatter: function (params) {
          return params.value.toLocaleString("pl-PL", {
            minimumFractionDigits: 2,
            maximumFractionDigits: 2
          });
        }
      }
    }]
  });
  chart.resize();
}
appsmith.onReady(() => {
  renderChart();
  appsmith.onModelChange(() => {
    renderChart();
  });
  window.addEventListener("resize", () => {
    if (chart) {
      chart.resize();
    }
  });
});

